// Build the JSDoc block from the description string
function buildJsDoc(description) {
    const descriptionLines = description.split("\n");
    if (descriptionLines.length === 1) {
        return [`/** ${descriptionLines[0]} */`];
    }
    return [
        "/**",
        ...descriptionLines.map(line => ` * ${line}`),
        " */",
    ];
}
export function generateIndexContent(config) {
    const lines = [
        "// GENERATED by nice-generate-exports — do not edit by hand",
        "// To update: edit package.exports.json and run `npm run generate-exports`",
        "",
    ];
    // JSDoc description
    if (config.description) {
        lines.push(...buildJsDoc(config.description));
        lines.push("");
    }
    // Default export — emitted before the wildcard so it reads top-down: default, then named
    if (config.default) {
        lines.push(`export { default } from "./components/${config.default}"`);
    }
    // Component wildcard exports
    for (const component of config.components) {
        lines.push(`export * from "./components/${component}"`);
    }
    // Token exports — all from ./tokens (the tokens/index.ts re-exports per-component wrappers)
    const tokens = config.tokens ?? [];
    if (tokens.length > 0) {
        const tokenExports = tokens
            .map(name => `${name}Styles, get${name}Token`)
            .join(", ");
        lines.push(`export { ${tokenExports} } from "./tokens"`);
    }
    // Constant exports
    const constants = config.constants ?? [];
    if (constants.length > 0) {
        lines.push(`export { ${constants.join(", ")} } from "./constants"`);
    }
    // Service exports
    const services = config.services ?? [];
    if (services.length > 0) {
        lines.push(`export { ${services.join(", ")} } from "./services"`);
    }
    // Trailing newline
    lines.push("");
    return lines.join("\n");
}
